export const getUploadPaymentScreenshotUrl = () => {
  return `/api/upload/payment`;
};

export const uploadPaymentScreenshot = async (
  uploadPaymentScreenshotBody: UploadPaymentScreenshotBody,
  options?: RequestInit,
): Promise<UploadResponse> => {
  const formData = new FormData();
  if (uploadPaymentScreenshotBody.file !== undefined) {
    formData.append(`file`, uploadPaymentScreenshotBody.file);
  }

  return customFetch<UploadResponse>(getUploadPaymentScreenshotUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

